using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() — returns JsonTypeInfo<T> directly (no cast needed)
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> => Type: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) TryGetTypeInfo<T>() — probe without throwing
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded: {info!.Type.Name}");
}

// Now demonstrate the "not available" path using a resolver that knows no types
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver
    {
        Modifiers = { (ti) => { if (ti.Type == typeof(Order)) throw new NotSupportedException(); } }
    }
};
// Lock the options so TryGetTypeInfo can be called
limited.MakeReadOnly(populateMissingResolver: false);

if (limited.TryGetTypeInfo<Order>(out JsonTypeInfo<Order>? orderInfo))
{
    Console.WriteLine($"Order info: {orderInfo!.Type.Name}");
}
else
{
    Console.WriteLine("TryGetTypeInfo<Order> returned false — no metadata available");
}

// Types used in the demo
public record Person(string Name, int Age);
public record Order(int Id, decimal Total);
EOF

